function mySqrt(x) {
  if (x === 0 || x === 1) return x;

  let left = 1;
  let right = x;
  let result = 0;

  while (left <= right) {
    const mid = left + Math.floor((right - left) / 2);

    // Avoid overflow by using division instead of multiplication
    if (mid <= x / mid) {
      result = mid;
      left = mid + 1;
    } else {
      right = mid - 1;
    }
  }

  return result;
}

